   260→/// JetSlowDeathBehavior - Handles cinematic death sequence for jets
   261→/// 
   262→/// This behavior manages a multi-stage death sequence for jet aircraft:
   263→/// 1. Initial death effects and sound
   264→/// 2. Falling with spinning animation
   265→/// 3. Optional secondary effects during fall
   266→/// 4. Ground impact effects
   267→/// 5. Final explosion after delay
   268→/// 
   269→/// The jet spins and falls realistically using physics and locomotor systems.
   270→#[derive(Debug)]
   271→pub struct JetSlowDeathBehavior {
   272→    /// Reference to the object this behavior is attached to
   273→    object: Arc<Mutex<dyn Object>>,
   274→    /// Configuration data for this behavior
   275→    module_data: Arc<JetSlowDeathBehaviorModuleData>,
   276→    /// Reference to game systems
   277→    game_logic: Arc<dyn GameLogic>,
   278→    terrain_logic: Arc<dyn TerrainLogic>,
   279→    audio: Arc<dyn Audio>,
   280→    global_data: Arc<dyn GlobalData>,
   281→
   282→    /// Frame we died on
   283→    timer_death_frame: UnsignedInt,
   284→    /// Frame we landed on the ground on
   285→    timer_on_ground_frame: UnsignedInt,
   286→    /// Current roll rate
   287→    roll_rate: Real,
   288→    /// Death loop sound instance
   289→    death_loop_sound: AudioEventRTS,
   290→    /// Whether slow death is activated
   291→    slow_death_activated: Bool,
   292→}
   293→
   294→impl JetSlowDeathBehavior {
   295→    /// Creates a new JetSlowDeathBehavior
   296→    pub fn new(
   297→        object: Arc<Mutex<dyn Object>>,
   298→        module_data: Arc<JetSlowDeathBehaviorModuleData>,
   299→        game_logic: Arc<dyn GameLogic>,
   300→        terrain_logic: Arc<dyn TerrainLogic>,
   301→        audio: Arc<dyn Audio>,
   302→        global_data: Arc<dyn GlobalData>,
   303→    ) -> Self {
   304→        Self {
   305→            object,
   306→            module_data,
   307→            game_logic,
   308→            terrain_logic,
   309→            audio,
   310→            global_data,
   311→            timer_death_frame: 0,
   312→            timer_on_ground_frame: 0,
   313→            roll_rate: 0.0,
   314→            death_loop_sound: AudioEventRTS::new(),
   315→            slow_death_activated: false,
   316→        }
   317→    }
   318→
   319→    /// Gets the module data for this behavior
   320→    pub fn get_jet_slow_death_behavior_module_data(&self) -> &JetSlowDeathBehaviorModuleData {
   321→        &self.module_data
   322→    }
   323→
   324→    /// Gets a reference to the object this behavior is attached to
   325→    pub fn get_object(&self) -> Arc<Mutex<dyn Object>> {
   326→        Arc::clone(&self.object)
   327→    }
   328→
   329→    /// Checks if slow death is activated
   330→    pub fn is_slow_death_activated(&self) -> Bool {
   331→        self.slow_death_activated
   332→    }
   333→
   334→    /// Called when the object dies - determines if ground death or slow death
   335→    pub fn on_die(&mut self, damage_info: Option<&DamageInfo>) -> Result<(), Box<dyn std::error::Error>> {
   336→        let object = self.object.lock().map_err(|_| "Failed to lock object")?;
   337→        
   338→        // If the jet is on the ground, do ground death
   339→        if !object.is_significantly_above_terrain() || object.get_status_bits().test(ObjectStatus::DeckHeightOffset) {
   340→            // Execute ground death effects
   341→            if let Some(ref fx) = self.module_data.fx_on_ground_death {
   342→                fx.do_fx_obj(&*object, None)?;
   343→            }
   344→
   345→            if let Some(ref ocl) = self.module_data.ocl_on_ground_death {
   346→                ocl.create(&*object, None)?;
   347→            }
   348→
   349→            // Clear deck height offset status
   350→            drop(object);
   351→            let mut object = self.object.lock().map_err(|_| "Failed to lock object")?;
   352→            object.clear_status(make_object_status_mask(ObjectStatus::DeckHeightOffset));
   353→            drop(object);
   354→
   355→            // Destroy object immediately
   356→            self.game_logic.destroy_object(Arc::clone(&self.object))?;
   357→        } else {
   358→            // Begin slow death sequence
   359→            self.begin_slow_death(damage_info)?;
   360→            
   361→            // Clear deck height offset status
   362→            drop(object);
   363→            let mut object = self.object.lock().map_err(|_| "Failed to lock object")?;
   364→            object.clear_status(make_object_status_mask(ObjectStatus::DeckHeightOffset));
   365→        }
   366→
   367→        Ok(())
   368→    }
   369→
   370→    /// Begins the slow death sequence for airborne jets
   371→    pub fn begin_slow_death(&mut self, _damage_info: Option<&DamageInfo>) -> Result<(), Box<dyn std::error::Error>> {
   372→        self.slow_death_activated = true;
   373→
   374→        let object = self.object.lock().map_err(|_| "Failed to lock object")?;
   375→
   376→        // Record the frame we died on
   377→        self.timer_death_frame = self.game_logic.get_frame();
   378→
   379→        // Do initial death effects
   380→        if let Some(ref fx) = self.module_data.fx_initial_death {
   381→            fx.do_fx_obj(&*object, None)?;
   382→        }
   383→
   384→        if let Some(ref ocl) = self.module_data.ocl_initial_death {
   385→            ocl.create(&*object, None)?;
   386→        }
   387→
   388→        // Start audio loop playing
   389→        self.death_loop_sound = self.module_data.death_loop_sound.clone();
   390→        if !self.death_loop_sound.is_empty() {
   391→            self.death_loop_sound.set_object_id(object.get_id());
   392→            let handle = self.audio.add_audio_event(&self.death_loop_sound);
   393→            self.death_loop_sound.set_playing_handle(handle);
   394→        }
   395→
   396→        // Initialize roll rate
   397→        self.roll_rate = self.module_data.roll_rate;
   398→
   399→        // Set the locomotor so that the plane starts falling
   400→        if let Some(ai) = object.get_ai_update_interface() {
   401→            let ai_guard = ai.lock().map_err(|_| "Failed to lock AI")?;
   402→            if let Some(locomotor) = ai_guard.get_cur_locomotor() {
   403→                let mut locomotor_guard = locomotor.lock().map_err(|_| "Failed to lock locomotor")?;
   404→                let gravity = self.global_data.get_gravity();
   405→                locomotor_guard.set_max_lift(-gravity * (1.0 - self.module_data.fall_how_fast));
   406→                locomotor_guard.set_max_turn_rate(0.0); // Prevent turning
   407→            }
   408→        }
   409→
   410→        Ok(())
   411→    }
   412→
   413→    /// Updates the death sequence - called every frame during slow death
   414→    pub fn update(&mut self) -> Result<UpdateSleepTime, Box<dyn std::error::Error>> {
   415→        if !self.slow_death_activated {
   416→            return Ok(UPDATE_SLEEP_NONE);
   417→        }
   418→
   419→        let object = self.object.lock().map_err(|_| "Failed to lock object")?;
   420→
   421→        // Roll the jet in the air
   422→        if let Some(physics) = object.get_physics() {
   423→            let mut physics_guard = physics.lock().map_err(|_| "Failed to lock physics")?;
   424→            physics_guard.set_roll_rate(self.roll_rate);
   425→        } else {
   426→            eprintln!(
   427→                "JetSlowDeathBehavior::update - '{}' has no physics",
   428→                object.get_template().get_name().as_str()
   429→            );
   430→        }
   431→
   432→        // Adjust the roll rate over time
   433→        self.roll_rate *= self.module_data.roll_rate_delta;
   434→
   435→        // Handle effects during flight
   436→        if self.timer_on_ground_frame == 0 {
   437→            // Check if we've hit the ground or a tree
   438→            let position = object.get_position();
   439→            let layer = self.terrain_logic.get_layer_for_destination(position);
   440→            
   441→            let height = if layer == PathfindLayerEnum::Ground {
   442→                // Use a simplified height calculation
   443→                let ground_height = self.terrain_logic.get_layer_height(position.x, position.y, layer);
   444→                position.z - ground_height
   445→            } else {
   446→                let layer_height = self.terrain_logic.get_layer_height(position.x, position.y, layer);
   447→                let height = position.z - layer_height;
   448→                // Add some tolerance for bridges
   449→                if height >= 0.0 && height <= 1.0 {
   450→                    0.0
   451→                } else {
   452→                    height
   453→                }
   454→            };
   455→
   456→            let mut hit_a_tree = false;
   457→            // Check for tree collision
   458→            if let Some(physics) = object.get_physics() {
   459→                let physics_guard = physics.lock().map_err(|_| "Failed to lock physics")?;
   460→                let tree_id = physics_guard.get_last_collidee();
   461→                if tree_id != 0 {
   462→                    // Simplified tree check - in real implementation would check object kind
   463→                    hit_a_tree = true;
   464→                }
   465→            }
   466→
   467→            // Check if we've hit the ground
   468→            if height <= 0.0 || hit_a_tree {
   469→                // Stop the death looping sound
   470→                self.audio.remove_audio_event(self.death_loop_sound.get_playing_handle());
   471→
   472→                // Do ground hit effects
   473→                if let Some(ref fx) = self.module_data.fx_hit_ground {
   474→                    fx.do_fx_obj(&*object, None)?;
   475→                }
   476→
   477→                if let Some(ref ocl) = self.module_data.ocl_hit_ground {
   478→                    ocl.create(&*object, None)?;
   479→                }
   480→
   481→                // We are now on the ground
   482→                self.timer_on_ground_frame = self.game_logic.get_frame();
   483→
   484→                // Start rolling on another axis
   485→                if let Some(physics) = object.get_physics() {
   486→                    let mut physics_guard = physics.lock().map_err(|_| "Failed to lock physics")?;
   487→                    physics_guard.set_pitch_rate(self.module_data.pitch_rate);
   488→                }
   489→            }
   490→
   491→            // Handle secondary effects timer
   492→            if self.timer_death_frame != 0 {
   493→                let current_frame = self.game_logic.get_frame();
   494→                if current_frame - self.timer_death_frame >= self.module_data.delay_secondary_from_initial_death {
   495→                    // Do secondary effects
   496→                    if let Some(ref fx) = self.module_data.fx_secondary {
   497→                        fx.do_fx_obj(&*object, None)?;
   498→                    }
   499→
   500→                    if let Some(ref ocl) = self.module_data.ocl_secondary {
   501→                        ocl.create(&*object, None)?;
   502→                    }
   503→
   504→                    // Clear the death frame timer since we've executed the event
   505→                    self.timer_death_frame = 0;
   506→                }
   507→            }
   508→        } else {
   509→            // We are on the ground, handle final explosion timer
   510→            let current_frame = self.game_logic.get_frame();
   511→            if current_frame - self.timer_on_ground_frame >= self.module_data.delay_final_blow_up_from_hit_ground {
   512→                // Do final explosion effects
   513→                if let Some(ref fx) = self.module_data.fx_final_blow_up {
   514→                    fx.do_fx_obj(&*object, None)?;
   515→                }
   516→
   517→                if let Some(ref ocl) = self.module_data.ocl_final_blow_up {
   518→                    ocl.create(&*object, None)?;
   519→                }
   520→
   521→                // Destroy the object - we're done
   522→                drop(object);
   523→                self.game_logic.destroy_object(Arc::clone(&self.object))?;
   524→            }
   525→        }
   526→
   527→        Ok(UPDATE_SLEEP_NONE)
   528→    }
   529→}
