   155→/// OverchargeBehavior - Handles power plant overcharge functionality
   156→/// 
   157→/// This behavior allows power plants to temporarily produce more power at the cost
   158→/// of health. Key features:
   159→/// - Toggleable overcharge state
   160→/// - Health drain while active
   161→/// - Automatic shutdown when health gets too low
   162→/// - UI notifications and radar events for the controlling player
   163→/// - Rod extension for visual feedback
   164→/// - Power bonus management with the owning player
   165→#[derive(Debug)]
   166→pub struct OverchargeBehavior {
   167→    /// Reference to the object this behavior is attached to
   168→    object: Arc<Mutex<dyn Object>>,
   169→    /// Configuration data for this behavior
   170→    module_data: Arc<OverchargeBehaviorModuleData>,
   171→    /// Reference to game systems
   172→    player_list: Arc<dyn PlayerList>,
   173→    in_game_ui: Arc<dyn InGameUI>,
   174→    radar: Arc<dyn Radar>,
   175→
   176→    /// Whether overcharge is currently active
   177→    overcharge_active: Bool,
   178→}
   179→
   180→impl OverchargeBehavior {
   181→    /// Creates a new OverchargeBehavior
   182→    pub fn new(
   183→        object: Arc<Mutex<dyn Object>>,
   184→        module_data: Arc<OverchargeBehaviorModuleData>,
   185→        player_list: Arc<dyn PlayerList>,
   186→        in_game_ui: Arc<dyn InGameUI>,
   187→        radar: Arc<dyn Radar>,
   188→    ) -> Self {
   189→        Self {
   190→            object,
   191→            module_data,
   192→            player_list,
   193→            in_game_ui,
   194→            radar,
   195→            overcharge_active: false,
   196→        }
   197→    }
   198→
   199→    /// Gets the module data for this behavior
   200→    pub fn get_overcharge_behavior_module_data(&self) -> &OverchargeBehaviorModuleData {
   201→        &self.module_data
   202→    }
   203→
   204→    /// Gets a reference to the object this behavior is attached to
   205→    pub fn get_object(&self) -> Arc<Mutex<dyn Object>> {
   206→        Arc::clone(&self.object)
   207→    }
   208→
   209→    /// Main update loop - handles health draining and automatic shutdown
   210→    pub fn update(&mut self) -> Result<UpdateSleepTime, Box<dyn std::error::Error>> {
   211→        if !self.overcharge_active {
   212→            return Ok(UPDATE_SLEEP_FOREVER);
   213→        }
   214→
   215→        let mut object = self.object.lock().map_err(|_| "Failed to lock object")?;
   216→
   217→        // Calculate and apply health drain
   218→        if let Some(body) = object.get_body_module() {
   219→            let body_guard = body.lock().map_err(|_| "Failed to lock body module")?;
   220→            let max_health = body_guard.get_max_health();
   221→            let current_health = body_guard.get_health();
   222→            drop(body_guard);
   223→
   224→            // Apply damage based on percentage drain rate
   225→            let drain_amount = (max_health * self.module_data.health_percent_to_drain_per_second) 
   226→                / LOGICFRAMES_PER_SECOND as Real;
   227→
   228→            let mut damage_info = DamageInfo {
   229→                amount: drain_amount,
   230→                source_id: object.get_id(),
   231→                damage_type: DamageType::Penalty,
   232→                death_type: DeathType::Normal,
   233→            };
   234→
   235→            object.attempt_damage(&mut damage_info)?;
   236→
   237→            // Check if health is below allowed threshold
   238→            let min_health_threshold = max_health * self.module_data.not_allowed_when_health_below_percent;
   239→            if current_health < min_health_threshold {
   240→                // Turn off overcharge due to low health
   241→                drop(object);
   242→                self.enable(false)?;
   243→
   244→                // Notify the controlling player
   245→                if let Ok(obj) = self.object.lock() {
   246→                    if let Some(player) = obj.get_controlling_player() {
   247→                        if let Some(local_player) = self.player_list.get_local_player() {
   248→                            if Arc::ptr_eq(&player, &local_player) {
   249→                                self.in_game_ui.message("GUI:OverchargeExhausted");
   250→                                if let Ok(obj_pos) = obj.get_position() {
   251→                                    self.radar.create_event(obj_pos, RadarEventType::Information);
   252→                                }
   253→                            }
   254→                        }
   255→                    }
   256→                }
   257→
   258→                return Ok(UPDATE_SLEEP_NONE);
   259→            }
   260→        }
   261→
   262→        Ok(UPDATE_SLEEP_NONE)
   263→    }
