   271→    /// Called when the module is being deleted
   272→    pub fn on_delete(&mut self) -> Result<(), Box<dyn std::error::Error>> {
   273→        if !self.overcharge_active {
   274→            return Ok(());
   275→        }
   276→
   277→        // Remove power bonus from the player
   278→        let object = self.object.lock().map_err(|_| "Failed to lock object")?;
   279→        if let Some(mut player) = object.get_controlling_player() {
   280→            player.remove_power_bonus(&*object);
