   287→    /// Called when object changes teams
   288→    pub fn on_capture(&mut self, old_owner: Option<Arc<dyn Player>>, new_owner: Option<Arc<dyn Player>>) -> Result<(), Box<dyn std::error::Error>> {
   289→        if !self.overcharge_active {
   290→            return Ok(());
   291→        }
